namespace sv_2c6a7ef0311e45bf9038a818d6f4d45f.Services;

public record Recipe(int Id, string Title, string Description, int PrepTimeMinutes);

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic pizza with fresh mozzarella, basil, and tomato sauce.", 30),
            new(2, "Spaghetti Carbonara", "Creamy pasta with pancetta, egg yolk, and pecorino cheese.", 25),
            new(3, "Tiramisu", "Layered dessert with espresso-soaked ladyfingers and mascarpone cream.", 45),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Tender chicken in a rich, spiced tomato-cream sauce.", 50),
            new(5, "Palak Paneer", "Fresh spinach curry with cubes of soft paneer cheese.", 35),
            new(6, "Biryani", "Fragrant basmati rice layered with spiced meat and caramelized onions.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Sushi Rolls", "Vinegared rice and fresh fish wrapped in nori seaweed.", 40),
            new(8, "Ramen", "Rich pork broth with noodles, soft-boiled egg, and chashu.", 90),
            new(9, "Tempura", "Lightly battered and fried shrimp and vegetables.", 20),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_2c6a7ef0311e45bf9038a818d6f4d45f.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation
@implements IDisposable

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

<nav>
    <a href="/recipes/1?sort=@_currentSort">Italian</a> |
    <a href="/recipes/2?sort=@_currentSort">Indian</a> |
    <a href="/recipes/3?sort=@_currentSort">Japanese</a>
</nav>

<div style="margin-top: 0.5rem;">
    <label>Sort:
        <select @bind="SelectedSort" @bind:after="OnSortChanged">
            <option value="newest">Newest</option>
            <option value="popular">Popular</option>
        </select>
    </label>
</div>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert" style="margin-top: 1rem;">
        <p>@_error</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p style="margin-top: 1rem;"><em>Loading recipes...</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p style="margin-top: 0.5rem; font-style: italic; color: gray;">Refreshing…</p>
    }

    <ul style="margin-top: 1rem;">
        @foreach (var recipe in DisplayedRecipes)
        {
            <li>
                <strong>@recipe.Title</strong> — @recipe.Description
                <br /><small>Prep time: @recipe.PrepTimeMinutes min</small>
            </li>
        }
    </ul>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;
    private string _currentSort = "newest";

    private CancellationTokenSource? _cts;

    private string SelectedSort
    {
        get => _currentSort;
        set => _currentSort = value;
    }

    private IEnumerable<Recipe> DisplayedRecipes =>
        _currentSort == "popular"
            ? _recipes!.OrderBy(r => r.PrepTimeMinutes)
            : _recipes!.OrderByDescending(r => r.Id);

    protected override async Task OnParametersSetAsync()
    {
        var sort = string.IsNullOrWhiteSpace(Sort) ? "newest" : Sort;
        _currentSort = sort is "newest" or "popular" ? sort : "newest";

        if (CuisineId == _loadedCuisineId && _recipes is not null)
        {
            // Only sort changed — no reload needed.
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request.
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _error = null;

        if (_recipes is not null)
        {
            _isRefreshing = true;
        }

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, token);

            // If cancelled during await, don't apply stale data.
            if (token.IsCancellationRequested)
                return;

            _recipes = results;
            _loadedCuisineId = CuisineId;
            _isRefreshing = false;
        }
        catch (OperationCanceledException)
        {
            // Request was superseded — do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
            _isRefreshing = false;
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong while loading recipes. Please try again.";
            _isRefreshing = false;
        }
    }

    private async Task Retry()
    {
        _error = null;
        await LoadRecipesAsync();
    }

    private void OnSortChanged()
    {
        Navigation.NavigateTo($"/recipes/{CuisineId}?sort={_currentSort}", replace: true);
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

