public record Recipe(int Id, string Title, string Description, int PrepTimeMinutes);

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic pizza with fresh mozzarella, basil, and tomato sauce.", 30),
            new(2, "Spaghetti Carbonara", "Creamy pasta with pancetta, egg yolk, and pecorino cheese.", 25),
            new(3, "Tiramisu", "Layered dessert with espresso-soaked ladyfingers and mascarpone cream.", 45),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Tender chicken in a rich, spiced tomato-cream sauce.", 50),
            new(5, "Palak Paneer", "Fresh spinach curry with cubes of soft paneer cheese.", 35),
            new(6, "Biryani", "Fragrant basmati rice layered with spiced meat and caramelized onions.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Sushi Rolls", "Vinegared rice and fresh fish wrapped in nori seaweed.", 40),
            new(8, "Ramen", "Rich pork broth with noodles, soft-boiled egg, and chashu.", 90),
            new(9, "Tempura", "Lightly battered and fried shrimp and vegetables.", 20),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

